import { toTags } from '../tag.js';
import { getItem } from './item.js';
import { toUserItem } from './user.js';
export const toEffectItem = (sonolus, localize, item) => ({
    name: item.name,
    source: sonolus.address,
    version: item.version,
    title: localize(item.title),
    subtitle: localize(item.subtitle),
    author: localize(item.author),
    authorUser: item.authorUser
        ? toUserItem(sonolus, localize, getItem(sonolus.user.items, item.authorUser, `Effect/${item.name}`, '.authorUser'))
        : undefined,
    tags: toTags(localize, item.tags),
    thumbnail: item.thumbnail,
    data: item.data,
    audio: item.audio,
});
